	runCmd(sideDir, "config", "user.name", "Side")
	runCmd(sideDir, "config", "user.email", "side@test.local")
	if err := os.WriteFile(filepath.Join(sideDir, "feature.txt"), []byte("origin-version\n"), 0o644); err != nil {
