// shortAttempt returns a 10-char slug derived from attemptID for use in temp
// branch names. When attemptID is empty, it returns the current timestamp.
func shortAttempt(attemptID string) string {
	if attemptID != "" {
		if len(attemptID) > 16 {
			return attemptID[:16]
		}
		return attemptID
	}
	return NowFunc().UTC().Format("20060102T150405")
}

// ApplyLandResultToExecuteBeadResult maps a LandResult onto an
// ExecuteBeadResult so the execute-bead loop sees the correct final status.
// It is the coordinator-pattern replacement for ApplyLandingToResult.
func ApplyLandResultToExecuteBeadResult(res *ExecuteBeadResult, land *LandResult) {
	if land == nil || res == nil {
		return
	}
	switch land.Status {
	case "landed":
		// Fast-forward or merge commit — either way the target branch now
		// contains the worker's result. ResultRev's own parent is still
		// BaseRev so replay fidelity is preserved.
		res.Outcome = "merged"
		res.Reason = ""
		res.PreserveRef = ""
		if land.Merged {
			res.Reason = "merged onto current tip"
		}
		if land.CheckoutSyncDeferred {
			detail := "checkout_sync_deferred"
			if len(land.CheckoutSyncDeferredPaths) > 0 {
				detail += ": " + strings.Join(land.CheckoutSyncDeferredPaths, ", ")
			}
			if res.Reason == "" {
				res.Reason = detail
			} else {
				res.Reason += "; " + detail
			}
		}
		// NewTip reflects the ref actually on the target branch (either
		// ResultRev on the ff path or the merge commit SHA on the merge path).
		if land.NewTip != "" {
			// Preserve the implementation rev before rewriting the compat alias.
			if res.ImplementationRev == "" {
				res.ImplementationRev = res.ResultRev
			}
			res.LandedRev = land.NewTip
			res.ResultRev = land.NewTip // backwards-compat alias mirrors LandedRev
		}
	case "preserved":
		res.Outcome = "preserved"
		res.Reason = land.Reason
		res.PreserveRef = land.PreserveRef
	case "no-changes":
		// Only overwrite when the worker itself did not already report
		// a richer no-changes rationale.
		if res.Outcome == "" || res.Outcome == ExecuteBeadOutcomeTaskSucceeded {
			res.Outcome = "no-changes"
		}
		if res.Reason == "" {
			res.Reason = land.Reason
		}
	}
	// Re-classify loop-visible status from the landing outcome.
	reasonForStatus := res.Reason
	if land.Status == "preserved" {
		// Route preserve reasons through the land-conflict classifier so the
		// loop sees land_conflict (not generic success).
		if strings.HasPrefix(res.Reason, PreMergeChecksReason) ||
			strings.HasPrefix(res.Reason, "evidence commit failed:") {
			reasonForStatus = res.Reason
		} else {
			reasonForStatus = "merge conflict"
		}
	}
	res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, reasonForStatus)
	res.OrchestratorStatus = res.Status
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
}

// BuildLandRequestFromResult constructs a LandRequest for the coordinator from
// an ExecuteBeadResult. The coordinator always passes projectRoot as the
// workdir — the worker's original worktree has already been cleaned up by the
// time Land() runs.
func BuildLandRequestFromResult(projectRoot string, res *ExecuteBeadResult) LandRequest {
	// Use the pre-landing implementation revision. If ImplementationRev is set
	// (i.e. the result was already landed once and ResultRev was rewritten to
	// the branch tip), prefer it so the coordinator always sees the candidate
	// commit rather than an already-landed or evidence rev.
	candidateRev := res.ImplementationRev
	if candidateRev == "" {
		candidateRev = res.ResultRev
	}
	return LandRequest{
		WorktreeDir:  projectRoot,
		BaseRev:      res.BaseRev,
		ResultRev:    candidateRev,
		BeadID:       res.BeadID,
		AttemptID:    res.AttemptID,
		TargetBranch: "",
		EvidenceDir:  res.ExecutionDir,
	}
}

	close(c.queue)
}

// run is the coordinator goroutine. It drains queue in FIFO order, calling
// agent.Land() for each submission. One submission at a time — this is the
// single-writer guarantee for target-ref writes on projectRoot.
func (c *LandCoordinator) run() {
	for sub := range c.queue {
		start := time.Now()
		result, err := agent.Land(c.projectRoot, sub.Request, c.gitOps)
		elapsed := time.Since(start)
		c.recordMetrics(sub.Request, result, err, elapsed)
		sub.replyCh <- landReply{result: result, err: err}
	}
}

// recordMetrics updates the in-memory metrics after a Land() call.
func (c *LandCoordinator) recordMetrics(req agent.LandRequest, result *agent.LandResult, err error, elapsed time.Duration) {
	const maxLastSubmissions = 10

	outcome := "failed"
	commitCount := 0
	if err == nil && result != nil {
		switch result.Status {
		case "landed":
			if result.PushFailed {
				outcome = "push_failed"
			} else {
				outcome = "landed"
			}
			commitCount = result.MergedCommitCount
		case "preserved":
			outcome = "preserved"
			commitCount = result.MergedCommitCount
		default:
			outcome = "failed"
		}
	}

	elapsedMS := elapsed.Milliseconds()

	c.metricsMu.Lock()
	defer c.metricsMu.Unlock()

	switch outcome {
	case "landed":
		c.metrics.Landed++
	case "preserved":
		c.metrics.Preserved++
	case "failed":
		c.metrics.Failed++
	case "push_failed":
		c.metrics.PushFailed++
		c.metrics.Landed++ // push_failed still landed locally
	}
	c.metrics.TotalDurationMS += elapsedMS
	c.metrics.TotalCommits += int64(commitCount)

	total := c.metrics.Landed + c.metrics.Preserved + c.metrics.Failed
	if total > 0 {
		c.metrics.PreservedRatio = float64(c.metrics.Preserved+c.metrics.Failed) / float64(total)
	}

	entry := LandOutcomeSummary{
		TS:          time.Now().UTC(),
		BeadID:      req.BeadID,
		AttemptID:   req.AttemptID,
		Outcome:     outcome,
		DurationMS:  elapsedMS,
		CommitCount: commitCount,
	}

